    s1_sl = my_exp(nu*d_initvalu_39*FoRT)*my_pow(d_initvalu_33,3.0f)*Cao;
    s2_junc = my_exp((nu-1.0f)*d_initvalu_39*FoRT)*my_pow(Nao,3.0f)*d_initvalu_36;
    s3_junc = (KmCai*my_pow(Nao,3.0f)*(1.0f+my_pow((d_initvalu_32/KmNai),3.0f))+my_pow(KmNao,3.0f)*d_initvalu_36+ my_pow(KmNai,3.0f)*Cao*(1.0f+d_initvalu_36/KmCai)+KmCao*my_pow(d_initvalu_32,3.0f)+my_pow(d_initvalu_32,3.0f)*Cao+my_pow(Nao,3.0f)*d_initvalu_36)*(1.0f+ksat*my_exp((nu-1.0f)*d_initvalu_39*FoRT));
    s2_sl = my_exp((nu-1.0f)*d_initvalu_39*FoRT)*my_pow(Nao,3.0f)*d_initvalu_37;
    s3_sl = (KmCai*my_pow(Nao,3.0f)*(1.0f+my_pow((d_initvalu_33/KmNai),3.0f)) + my_pow(KmNao,3.0f)*d_initvalu_37+my_pow(KmNai,3.0f)*Cao*(1.0f+d_initvalu_37/KmCai)+KmCao*my_pow(d_initvalu_33,3.0f)+my_pow(d_initvalu_33,3.0f)*Cao+my_pow(Nao,3.0f)*d_initvalu_37)*(1.0f+ksat*my_exp((nu-1.0f)*d_initvalu_39*FoRT));
    I_ncx_junc = Fjunc*IbarNCX*my_pow(Q10NCX,Qpow)*Ka_junc*(s1_junc-s2_junc)/s3_junc;
    I_ncx_sl = Fsl*IbarNCX*my_pow(Q10NCX,Qpow)*Ka_sl*(s1_sl-s2_sl)/s3_sl;
    I_ncx = I_ncx_junc+I_ncx_sl;
    finavalu[offset_45]=2.0f*I_ncx*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    I_pca_junc = Fjunc*my_pow(Q10SLCaP,Qpow)*IbarSLCaP*my_pow(d_initvalu_36,1.6f)/(my_pow(KmPCa,1.6f)+my_pow(d_initvalu_36,1.6f));
    I_pca_sl = Fsl*my_pow(Q10SLCaP,Qpow)*IbarSLCaP*my_pow(d_initvalu_37,1.6f)/(my_pow(KmPCa,1.6f)+my_pow(d_initvalu_37,1.6f));
    I_pca = I_pca_junc+I_pca_sl;
    finavalu[offset_44]=-I_pca*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    I_cabk_junc = Fjunc*GCaB*(d_initvalu_39-eca_junc);
    I_cabk_sl = Fsl*GCaB*(d_initvalu_39-eca_sl);
    I_cabk = I_cabk_junc+I_cabk_sl;
    finavalu[offset_46]=-I_cabk*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    MaxSR = 15.0f; 
    MinSR = 1.0f;
    kCaSR = MaxSR - (MaxSR-MinSR)/(1.0f+my_pow(ec50SR/d_initvalu_31,2.5f));
    koSRCa = koCa/kCaSR;
    kiSRCa = kiCa*kCaSR;
    RI = 1.0f-d_initvalu_14-d_initvalu_15-d_initvalu_16;
    finavalu[offset_14] = (kim*RI-kiSRCa*d_initvalu_36*d_initvalu_14)-(koSRCa*my_pow(d_initvalu_36,2.0f)*d_initvalu_14-kom*d_initvalu_15);			
    finavalu[offset_15] = (koSRCa*my_pow(d_initvalu_36,2.0f)*d_initvalu_14-kom*d_initvalu_15)-(kiSRCa*d_initvalu_36*d_initvalu_15-kim*d_initvalu_16);			
    finavalu[offset_16] = (kiSRCa*d_initvalu_36*d_initvalu_15-kim*d_initvalu_16)-(kom*d_initvalu_16-koSRCa*my_pow(d_initvalu_36,2.0f)*RI);			
    J_SRCarel = ks*d_initvalu_15*(d_initvalu_31-d_initvalu_36);					
    J_serca = my_pow(Q10SRCaP,Qpow)*Vmax_SRCaP*(my_pow((d_initvalu_38/Kmf),hillSRCaP)-my_pow((d_initvalu_31/Kmr),hillSRCaP))
                                             /(1.0f+my_pow((d_initvalu_38/Kmf),hillSRCaP)+my_pow((d_initvalu_31/Kmr),hillSRCaP));
    J_SRleak = 5.348e-6f*(d_initvalu_31-d_initvalu_36);			

    finavalu[offset_17] = kon_na*d_initvalu_32*(Bmax_Naj-d_initvalu_17)-koff_na*d_initvalu_17;								
    finavalu[offset_18] = kon_na*d_initvalu_33*(Bmax_Nasl-d_initvalu_18)-koff_na*d_initvalu_18;							

    finavalu[offset_19] = kon_tncl*d_initvalu_38*(Bmax_TnClow-d_initvalu_19)-koff_tncl*d_initvalu_19;						
    finavalu[offset_20] = kon_tnchca*d_initvalu_38*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchca*d_initvalu_20;			
    finavalu[offset_21] = kon_tnchmg*Mgi*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchmg*d_initvalu_21;				
    finavalu[offset_22] = 0.0f;																		
    finavalu[offset_23] = kon_myoca*d_initvalu_38*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myoca*d_initvalu_23;				
    finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myomg*d_initvalu_24;				
    finavalu[offset_25] = kon_sr*d_initvalu_38*(Bmax_SR-d_initvalu_25)-koff_sr*d_initvalu_25;								
    J_CaB_cytosol = finavalu[offset_19] + finavalu[offset_20] + finavalu[offset_21] + finavalu[offset_22] + finavalu[offset_23] + finavalu[offset_24] + finavalu[offset_25];

    finavalu[offset_26] = kon_sll*d_initvalu_36*(Bmax_SLlowj-d_initvalu_26)-koff_sll*d_initvalu_26;						
    finavalu[offset_27] = kon_sll*d_initvalu_37*(Bmax_SLlowsl-d_initvalu_27)-koff_sll*d_initvalu_27;						
    finavalu[offset_28] = kon_slh*d_initvalu_36*(Bmax_SLhighj-d_initvalu_28)-koff_slh*d_initvalu_28;						
    finavalu[offset_29] = kon_slh*d_initvalu_37*(Bmax_SLhighsl-d_initvalu_29)-koff_slh*d_initvalu_29;						
    J_CaB_junction = finavalu[offset_26]+finavalu[offset_28];
    J_CaB_sl = finavalu[offset_27]+finavalu[offset_29];

    finavalu[offset_30] = kon_csqn*d_initvalu_31*(Bmax_Csqn-d_initvalu_30)-koff_csqn*d_initvalu_30;						
    oneovervsr = 1.0f/Vsr;
    finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-finavalu[offset_30];   

    I_Na_tot_junc = I_Na_junc+I_nabk_junc+3.0f*I_ncx_junc+3.0f*I_nak_junc+I_CaNa_junc;		
    I_Na_tot_sl = I_Na_sl+I_nabk_sl+3.0f*I_ncx_sl+3.0f*I_nak_sl+I_CaNa_sl;					
    finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(d_initvalu_33-d_initvalu_32)-finavalu[offset_17];
    oneovervsl = 1.0f/Vsl;
    finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(d_initvalu_32-d_initvalu_33)+J_na_slmyo*oneovervsl*(d_initvalu_34-d_initvalu_33)-finavalu[offset_18];
    finavalu[offset_34] = J_na_slmyo/Vmyo*(d_initvalu_33-d_initvalu_34);											

    I_K_tot = I_to+I_kr+I_ks+I_ki-2.0f*I_nak+I_CaK+I_kp;									
    finavalu[offset_35] = 0.0f;															

    I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2.0f*I_ncx_junc;						
    I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2.0f*I_ncx_sl;								
    finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2.0f*Frdy)+J_ca_juncsl/Vjunc*(d_initvalu_37-d_initvalu_36)
             - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;				
    finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2.0f*Frdy)+J_ca_juncsl/Vsl*(d_initvalu_36-d_initvalu_37)
             + J_ca_slmyo/Vsl*(d_initvalu_38-d_initvalu_37)-J_CaB_sl;									
    finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

    state = 1;			
    switch(state){
        case 0:
            I_app = 0.0f;
            break;
        case 1:			
            if(my_fmod(timeinst,cycleLength) <= 5.0f){
                I_app = 9.5f;
            }
            else{
                I_app = 0.0f;
            }
            break;
        case 2:     
            V_hold = -55.0f;
            V_test = 0.0f;
            if(timeinst>0.5f && timeinst<200.5f){
                V_clamp = V_test;
            }
            else{
                V_clamp = V_hold;
            }
            R_clamp = 0.04f;
            I_app = (V_clamp-d_initvalu_39)/R_clamp;
            break;
    } 

    I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;				
    I_Cl_tot = I_ClCa+I_Clbk;							
    I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
    I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
    finavalu[offset_39] = -(I_tot-I_app);

    finavalu[offset_41] = 0.0f;
    finavalu[offset_42] = 0.0f;

}

void kernel_fin(global fp *initvalu,
                int initvalu_offset_ecc,
                int initvalu_offset_Dyad,
                int initvalu_offset_SL,
                int initvalu_offset_Cyt,
                global fp *parameter,
                global fp *finavalu,
                fp JCaDyad,
                fp JCaSL,
                fp JCaCyt){

    fp BtotDyad;			
    fp CaMKIItotDyad;		

    fp Vmyo;			
    fp Vdyad;			
    fp VSL;				

    fp kSLmyo;			
    fp k0Boff;			
    fp k0Bon;			
    fp k2Boff;			
    fp k2Bon;	
    fp k4Bon;			
    fp CaMtotDyad;
    fp Bdyad;			
    fp J_cam_dyadSL;		
    fp J_ca2cam_dyadSL;		
    fp J_ca4cam_dyadSL;		
    fp J_cam_SLmyo;		
    fp J_ca2cam_SLmyo;		
    fp J_ca4cam_SLmyo;		

    BtotDyad      = parameter[2];						
    CaMKIItotDyad = parameter[3];					

    Vmyo = 2.1454e-11f;		
    Vdyad = 1.7790e-14f;		
    VSL = 6.6013e-13f;		

    kSLmyo = 8.587e-15f;		
    k0Boff = 0.0014f;		
    k0Bon = k0Boff/0.2f;		
    k2Boff = k0Boff/100.0f;	
    k2Bon = k0Bon;	
    k4Bon = k0Bon;			

    finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3f*JCaDyad;
    finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3f*JCaSL;
    finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3f*JCaCyt; 

    CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
               + initvalu[initvalu_offset_Dyad+1]
               + initvalu[initvalu_offset_Dyad+2]
               + initvalu[initvalu_offset_Dyad+3]
               + initvalu[initvalu_offset_Dyad+4]
               + initvalu[initvalu_offset_Dyad+5]
               + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
                                  + initvalu[initvalu_offset_Dyad+7]
                                  + initvalu[initvalu_offset_Dyad+8]
                                  + initvalu[initvalu_offset_Dyad+9])
               + initvalu[initvalu_offset_Dyad+12]
               + initvalu[initvalu_offset_Dyad+13]
               + initvalu[initvalu_offset_Dyad+14];
    Bdyad = BtotDyad - CaMtotDyad;																				
    J_cam_dyadSL = 1e-3f * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);			
    J_ca2cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);		
    J_ca4cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);		

    J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);								
    J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);							
    J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);							

    finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
    finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
    finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

    finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
    finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
    finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

    finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
    finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
    finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;

}

void kernel_fin_2(int timeinst,
                  global fp* d_initvalu,
                  global fp* d_finavalu,
                  int offset_ecc,
                  int offset_Dyad,
                  int offset_SL,
                  int offset_Cyt,
                  global fp* d_params,
                  global fp* d_com){

    fp BtotDyad;
    fp CaMKIItotDyad;

    fp Vmyo;			
    fp Vdyad;			
    fp VSL;				

    fp kSLmyo;			
    fp k0Boff;			
    fp k0Bon;			
    fp k2Boff;			
    fp k2Bon;	
    fp k4Bon;			
    fp CaMtotDyad;
    fp Bdyad;			
    fp J_cam_dyadSL;		
    fp J_ca2cam_dyadSL;		
    fp J_ca4cam_dyadSL;		
    fp J_cam_SLmyo;		
    fp J_ca2cam_SLmyo;		
    fp J_ca4cam_SLmyo;		

    BtotDyad = d_params[1];
    CaMKIItotDyad = d_params[2];

    d_finavalu[offset_ecc+35] = d_finavalu[offset_ecc+35] + 1e-3f*d_com[0];
    d_finavalu[offset_ecc+36] = d_finavalu[offset_ecc+36] + 1e-3f*d_com[1];
    d_finavalu[offset_ecc+37] = d_finavalu[offset_ecc+37] + 1e-3f*d_com[2]; 

    Vmyo = 2.1454e-11f;	
    Vdyad = 1.7790e-14f;	
    VSL = 6.6013e-13f;	

    kSLmyo = 8.587e-15f;	
    k0Boff = 0.0014f;	
    k0Bon = k0Boff/0.2f;	
    k2Boff = k0Boff/100.0f;	
    k2Bon = k0Bon;	
    k4Bon = k0Bon;	
    CaMtotDyad = d_initvalu[offset_Dyad+0]
               + d_initvalu[offset_Dyad+1]
               + d_initvalu[offset_Dyad+2]
               + d_initvalu[offset_Dyad+3]
               + d_initvalu[offset_Dyad+4]
               + d_initvalu[offset_Dyad+5]
               + CaMKIItotDyad * (	  d_initvalu[offset_Dyad+6]
                                                  + d_initvalu[offset_Dyad+7]
                                                  + d_initvalu[offset_Dyad+8]
                                                  + d_initvalu[offset_Dyad+9])
               + d_initvalu[offset_Dyad+12]
               + d_initvalu[offset_Dyad+13]
               + d_initvalu[offset_Dyad+14];
    Bdyad = BtotDyad - CaMtotDyad;																				
    J_cam_dyadSL = 1e-3f * (  k0Boff*d_initvalu[offset_Dyad+0] - k0Bon*Bdyad*d_initvalu[offset_SL+0]);			
    J_ca2cam_dyadSL = 1e-3f * (  k2Boff*d_initvalu[offset_Dyad+1] - k2Bon*Bdyad*d_initvalu[offset_SL+1]);		
    J_ca4cam_dyadSL = 1e-3f * (  k2Boff*d_initvalu[offset_Dyad+2] - k4Bon*Bdyad*d_initvalu[offset_SL+2]);		

    J_cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+0] - d_initvalu[offset_Cyt+0]);								
    J_ca2cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+1] - d_initvalu[offset_Cyt+1]);							
    J_ca4cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+2] - d_initvalu[offset_Cyt+2]);							

    d_finavalu[offset_Dyad+0] = d_finavalu[offset_Dyad+0] - J_cam_dyadSL;
    d_finavalu[offset_Dyad+1] = d_finavalu[offset_Dyad+1] - J_ca2cam_dyadSL;
    d_finavalu[offset_Dyad+2] = d_finavalu[offset_Dyad+2] - J_ca4cam_dyadSL;

    d_finavalu[offset_SL+0] = d_finavalu[offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
    d_finavalu[offset_SL+1] = d_finavalu[offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
    d_finavalu[offset_SL+2] = d_finavalu[offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

    d_finavalu[offset_Cyt+0] = d_finavalu[offset_Cyt+0] + J_cam_SLmyo/Vmyo;
    d_finavalu[offset_Cyt+1] = d_finavalu[offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
    d_finavalu[offset_Cyt+2] = d_finavalu[offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;

}

void kernel_ecc(fp timeinst,
                global fp* d_initvalu,
                global fp* d_finavalu,
                global fp* d_params,
                global fp* d_com){

    fp CaDyad;			
    fp CaSL;				
    fp CaCyt;			

    fp JCaDyad;
    fp JCaSL;
    fp JCaCyt;

    CaDyad = d_initvalu[35]*1e3f;
    JCaDyad = cam(timeinst, d_initvalu, 46, d_params, 0, d_finavalu, CaDyad);

    CaSL = d_initvalu[36]*1e3f;
    JCaSL = cam(timeinst, d_initvalu, 61, d_params, 5, d_finavalu, CaSL);

    CaCyt = d_initvalu[37]*1e3f;
    JCaCyt = cam(timeinst, d_initvalu, 76, d_params, 10, d_finavalu, CaCyt);

    kernel_ecc_2(timeinst, d_initvalu, d_finavalu, 0, d_params);

    d_com[0] = JCaDyad;
    d_com[1] = JCaSL;
    d_com[2] = JCaCyt;

    kernel_fin(timeinst, d_initvalu, d_finavalu, 0, 46, 61, 76, d_params, d_com);

    int i;
    for(i=0; i<EQUATIONS; i++){
        if (my_isnan(d_finavalu[i]) == 1){ 
            d_finavalu[i] = 0.0001f;												
        }
        else if (my_isinf(d_finavalu[i]) == 1){ 
            d_finavalu[i] = 0.0001f;												
        }
    }
}

void kernel_2(int timeinst,
              global fp* initvalu,
              global fp* params,
              global fp* finavalu,
              global fp* com){

    fp CaDyad;			
    fp CaSL;				
    fp CaCyt;			

    fp JCaDyad;
    fp JCaSL;
    fp JCaCyt;

    CaDyad = initvalu[35]*1e3f;
    JCaDyad = cam(timeinst, initvalu, 46, params, 0, finavalu, CaDyad);

    CaSL = initvalu[36]*1e3f;
    JCaSL = cam(timeinst, initvalu, 61, params, 5, finavalu, CaSL);

    CaCyt = initvalu[37]*1e3f;
    JCaCyt = cam(timeinst, initvalu, 76, params, 10, finavalu, CaCyt);

    kernel_ecc_2(timeinst, initvalu, finavalu, 0, params);

    com[0] = JCaDyad;
    com[1] = JCaSL;
    com[2] = JCaCyt;

    kernel_fin_2(timeinst, initvalu, finavalu, 0, 46, 61, 76, params, com);

    int i;
    for(i=0; i<EQUATIONS; i++){
        if (my_isnan(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001f;												
        }
        else if (my_isinf(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001f;												
        }
    }
}

__attribute__((always_inline)) fp my_max(fp x, fp y) {
    return (x < y) ? y : x;
}

