void solver_2(int workload,
              int xmax,
              global fp* x,
              global fp* y,
              global fp* params,
              global fp* com,
              global fp* err,
              global fp* scale,
              global fp* yy,
              global fp* initvalu_temp,
              global fp* finavalu_temp){

    int tid;

    long y_pointer_initial;
    long y_pointer_current; 
    long x_pointer_current;
    int err_pointer;
    int scale_pointer;
    int yy_pointer;
    int params_pointer;
    int initvalu_temp_pointer;
    int finavalu_temp_pointer;
    int com_pointer;

    fp err_exponent ;
    fp h_init;
    fp h;
    fp tolerance;
    int xmin;

    int error;
    int outside;
    fp scale_min;
    fp scale_fina;

    int i, j, k;

    tid = get_global_id(0);

    if (tid >= workload) return;

    err_pointer = tid*EQUATIONS;
    scale_pointer = tid*EQUATIONS;
    yy_pointer = tid*EQUATIONS;
    params_pointer = tid*PARAMETERS;
    initvalu_temp_pointer = tid*EQUATIONS;
    finavalu_temp_pointer = tid*13*EQUATIONS;
    com_pointer = tid*3;

    err_exponent = 1.0f / 7.0f;
    h_init = 1.0f;
    h = h_init;
    xmin = 0;
    tolerance = 10.0f / (fp)(xmax - xmin);

    if (xmax < xmin || h <= 0.0f){
        return;
    }

    if (xmax == xmin){
        return; 
    }

    if (h > (xmax - xmin) ) { 
        h = (fp)xmax - (fp)xmin; 
    }

    for(k=1; k<(xmax+1); k++) {											

        y_pointer_initial = tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
        y_pointer_current = tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
        x_pointer_current = tid*(xmax+1)+k;

        x[x_pointer_current] = (fp)k;							
        h = h_init;

        scale_fina = 1.0f;

        for (j = 0; j < 12; j++) {

            error = 0;
            outside = 0;
            scale_min = 4.0f;

            embedded_fehlberg_7_8_2(h,																												

                                    x[x_pointer_current],																				
                                    &y[y_pointer_initial],																					
                                    &y[y_pointer_current],																				
                                    &params[params_pointer],																		

                                    &err[err_pointer],																						
                                    &initvalu_temp[initvalu_temp_pointer],													
                                    &finavalu_temp[finavalu_temp_pointer],													
                                    &com[com_pointer]);

            for(i=0; i<EQUATIONS; i++){
                if(err[err_pointer+i] > 0.0f){
                    error = 1;
                }
            }
            if (error != 1) {
                scale_fina = 4.0f; 
                break;
            }

            for(i=0; i<EQUATIONS; i++){
                if(y[y_pointer_initial+i] == 0.0f){
                    yy[yy_pointer+i] = tolerance;
                }
                else{
                    yy[yy_pointer+i] = my_fabs(y[y_pointer_initial+i]);
                }
                scale[scale_pointer+i] = 0.8f * my_pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
                if(scale[scale_pointer+i]<scale_min){
                    scale_min = scale[scale_pointer+i];
                }
            }
            scale_fina = my_min( my_max(scale_min,0.125f), 4.0f);

            for(i=0; i<EQUATIONS; i++){
                if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
                    outside = 1;
                }
            }
            if (outside == 0){
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9f) {
                h = 0.9f;
            }

            if ( x[x_pointer_current] + h > (fp)xmax ){
                h = (fp)xmax - x[x_pointer_current];
            }

            else if ( x[x_pointer_current] + h + 0.5f * h > (fp)xmax ){
                h = 0.5f * h;
            }

        }

        x[x_pointer_current] = x[x_pointer_current] + h;

        if ( j >= 12 ) {
            continue; 
        }

    }
}

