#include <CL/cl.h>

typedef float fp;

/**
 * Kernel: prepare_kernel
 * Initializes sums for reduction. 
 * Note: The exponential transformation is performed in extract_kernel.
 */
__kernel void prepare_kernel(long d_Ne,
                             global fp *d_I,
                             global fp *d_sums,
                             global fp *d_sums2) {
    int idx = get_global_id(0);

    if (idx < d_Ne) {
        fp val = d_I[idx];
        d_sums[idx] = val;
        d_sums2[idx] = val * val;
    }
}

/**
 * Kernel: reduce_kernel
 * Performs parallel reduction.
 */
__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            global fp *d_sums,
                            global fp *d_sums2,
                            int blocks2_work_size) {

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * get_local_size(0)) + tx;

    int total_threads = get_num_groups(0) * get_local_size(0);
    int nf = get_local_size(0) - (total_threads - d_no);
    int df = 0;

    // Use a safe size for local memory. 256 is common. 
    // If the device uses larger workgroups, this might need adjustment, 
    // but 256 is a safe default for portability in absence of macros.
    local fp d_psum[256];
    local fp d_psum2[256];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == get_local_size(0)) {
        for (i = 2; i <= get_local_size(0); i = i * 2) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (get_local_size(0) - 1)) {
            d_sums[bx * d_mul * get_local_size(0)] = d_psum[tx];
            d_sums2[bx * d_mul * get_local_size(0)] = d_psum2[tx];
        }
    } else {
        if (bx != (get_num_groups(0) - 1)) {
            for (i = 2; i <= get_local_size(0); i = i * 2) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (get_local_size(0) - 1)) {
                d_sums[bx * d_mul * get_local_size(0)] = d_psum[tx];
                d_sums2[bx * d_mul * get_local_size(0)] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= get_local_size(0); i = i * 2) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = i * 2) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                int start_idx = (bx * get_local_size(0)) + df;
                int end_idx = (bx * get_local_size(0)) + nf;
                for (i = start_idx; i < end_idx; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * get_local_size(0)] = d_psum[tx];
                d_sums2[bx * d_mul * get_local_size(0)] = d_psum2[tx];
            }
        }
    }
}

/**
 * Kernel: srad_kernel
 * Computes coefficients.
 */
__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          global int *d_iN,
                          global int *d_iS,
                          global int *d_jE,
                          global int *d_jW,
                          global fp *d_dN,
                          global fp *d_dS,
                          global fp *d_dW,
                          global fp *d_dE,
                          fp q0sqr,
                          global fp *d_c,
                          global fp *d_I) {

    int idx = get_global_id(0);

    if (idx < Ne) {
        int i = idx / Nc;
        int j = idx % Nc;

        fp Jc = d_I[idx];

        fp dN_val = d_I[d_iN[i] * Nc + j] - Jc;
        fp dS_val = d_I[d_iS[i] * Nc + j] - Jc;
        fp dW_val = d_I[i * Nc + d_jW[j]] - Jc;
        fp dE_val = d_I[i * Nc + d_jE[j]] - Jc;

        d_dN[idx] = dN_val;
        d_dS[idx] = dS_val;
        d_dW[idx] = dW_val;
        d_dE[idx] = dE_val;

        fp G2 = (dN_val*dN_val + dS_val*dS_val + dW_val*dW_val + dE_val*dE_val) / (Jc*Jc);
        fp L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        fp num = (0.5f * G2) - ((1.0f/16.0f) * (L*L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        d_c[idx] = c_val;
    }
}

/**
