                           global fp *d_dS,
                           global fp *d_dW,
                           global fp *d_dE,
                           global fp *d_c,
                           global fp *d_I) {

    int idx = get_global_id(0);

    if (idx < Ne) {
        int i = idx / Nc;
        int j = idx % Nc;

        fp cN = d_c[idx];
        fp cS = d_c[d_iS[i] * Nc + j];
        fp cW = d_c[idx];
        fp cE = d_c[i * Nc + d_jE[j]];

        fp D = cN * d_dN[idx] + cS * d_dS[idx] + cW * d_dW[idx] + cE * d_dE[idx];

        d_I[idx] = d_I[idx] + 0.25f * lambda * D;
    }
}

/**
 * Kernel: extract_kernel
 * Transforms input (assumed 0-255) to log-intensity domain or similar.
 * Matches CUDA reference: exp(x/255).
 */
__kernel void extract_kernel(long d_Ne,
                             global fp *d_I) {
    int idx = get_global_id(0);

    if (idx < d_Ne) {
        d_I[idx] = exp(d_I[idx] / 255.0f);
    }
}

/**
 * Kernel: compress_kernel
 * Transforms output back.
 * Matches CUDA reference: log(x)*255.
 */
