__global__ void reduce_kernel(long d_Ne, long d_no, int d_mul, fp *d_sums, fp *d_sums2, int blocks2_work_size) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;
    int nf = NUMBER_THREADS - (gridDim.x * NUMBER_THREADS - d_no);
    int df = 0;

    extern __shared__ fp d_psum[NUMBER_THREADS];
    extern __shared__ fp d_psum2[NUMBER_THREADS];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    }

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            __syncthreads();
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (gridDim.x - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                __syncthreads();
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                __syncthreads();
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

__global__ void srad_kernel(fp lambda, int Nr, int Nc, long Ne, int *d_iN, int *d_iS, int *d_jE, int *d_jW, fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE, fp q0sqr, fp *d_c, fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < Ne) {
        int i = ei / Nc;
        int j = ei % Nc;
        int k = ei;

        fp Jc = d_I[k];
        fp dN_val = d_I[d_iN[i] * Nc + j] - Jc;
        fp dS_val = d_I[d_iS[i] * Nc + j] - Jc;
        fp dW_val = d_I[i * Nc + d_jW[j]] - Jc;
        fp dE_val = d_I[i * Nc + d_jE[j]] - Jc;

        d_dN[k] = dN_val;
        d_dS[k] = dS_val;
        d_dW[k] = dW_val;
        d_dE[k] = dE_val;

        fp G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
        fp L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        fp num = (0.5 * G2) - ((1.0 / 16.0) * (L * L));
        fp den = 1 + (0.25 * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
        fp c_val = 1.0 / (1.0 + den);

        if (c_val < 0.0) c_val = 0.0;
        else if (c_val > 1.0) c_val = 1.0;

        d_c[k] = c_val;
    }
}

__global__ void srad2_kernel(fp lambda, int Nr, int Nc, long Ne, int *d_iN, int *d_iS, int *d_jE, int *d_jW, fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE, fp *d_c, fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < Ne) {
        int i = ei / Nc;
        int j = ei % Nc;
        int k = ei;

        fp cN = d_c[k];
        fp cS = d_c[d_iS[i] * Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[i * Nc + d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25 * lambda * D;
    }
}

__global__ void compress_kernel(long d_Ne, fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

