__kernel void pgain_kernel(
    const global Point_Struct* p,
    const global float* coord,
    global float* work_mem,
    const global int* center_table,
    global char* switch_membership,
    int num,
    int dim,
    long x,
    int K) {
  int i = get_global_id(0);
  if (i >= num) return;

  // Calculate distance squared between point i and point x
  float x_cost = 0.0f;
  for (int d = 0; d < dim; d++) {
    float diff = coord[d * num + i] - coord[d * num + x];
    x_cost += diff * diff;
  }
  x_cost *= p[i].weight;

  float current_cost = p[i].cost;

  if (x_cost < current_cost) {
    switch_membership[i] = 1;
    // Accumulate cost difference in the last column (index K) of row i
    work_mem[i * (K + 1) + K] += x_cost - current_cost;
  } else {
    int assign = (int)p[i].assign;
    // Ensure assign is within valid range before accessing center_table
    if (assign >= 0 && assign < num) {
      int ct = center_table[assign];
      // Ensure ct is within valid range [0, K-1] before accessing work_mem
      if (ct >= 0 && ct < K) {
        work_mem[i * (K + 1) + ct] += current_cost - x_cost;
      }
    }
  }
}

