float dist_kernel(Point_Fixed p1, Point_Fixed p2, int dim) {
    float result = 0.0f;
    for (int i = 0; i < dim; i++) {
        float d = get_coord(p1, i, dim) - get_coord(p2, i, dim);
        result += d * d;
    }
    return result;
}

__kernel void pgain_kernel(
    global Point_Struct *p,
    global float *coord,
    global float *work_mem,
    global int *center_table,
    global char *switch_membership,
    local float *local_coord,
    int num,
    int dim,
    long x,
    int K
) {
    int idx = get_global_id(0);
    if (idx >= num) return;

    int tid = get_local_id(0);

    // Load coordinates into local memory
    for (int d = tid; d < dim; d += THREADS_PER_BLOCK) {
        local_coord[d * THREADS_PER_BLOCK + tid] = coord[idx * dim + d];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Construct Point_Fixed for x (the candidate center)
    // Since x is fixed for all threads in this kernel call, we can just read from global or use the local copy if available.
    // However, to match the logic where each thread needs px, and px is the same for all, 
    // we will construct it using the global coord array for index x, as local_coord holds coord[idx].
    // Wait, the original logic computes dist(points->p[i], points->p[x]).
    // In the kernel, 'idx' corresponds to 'i'.
    // So we need pi (from idx) and px (from x).

    Point_Fixed px;
    // Load px from global memory directly since it's the same for all threads and x is a specific index
    for (int d = 0; d < dim; d++) {
        set_coord(&px, d, coord[x * dim + d], dim);
    }

    Point_Fixed pi;
    // Load pi from local memory (which holds coord[idx])
    for (int d = 0; d < dim; d++) {
        set_coord(&pi, d, local_coord[d * THREADS_PER_BLOCK + tid], dim);
    }

    float x_cost = dist_kernel(pi, px, dim) * p[idx].weight;
    float current_cost = p[idx].cost;

    if (x_cost < current_cost) {
        switch_membership[idx] = 1;
        work_mem[idx * (K + 1) + K] += (x_cost - current_cost);
    } else {
        int assign = p[idx].assign;
        int ct_val = center_table[assign];
        if (ct_val >= 0 && ct_val < K) {
            work_mem[idx * (K + 1) + ct_val] += (current_cost - x_cost);
        }
    }
}

#define THREADS_PER_BLOCK 256

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__kernel void pgain_kernel(
    const global Point_Struct* p,
    const global float* coord,
    global float* work_mem,
    const global int* center_table,
    global char* switch_membership,
    long x,
    int K,
    int num,
    int dim) {

    int i = get_global_id(0);
    if (i >= num) return;

    // Calculate distance to candidate center x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += (x_cost - current_cost);
    } else {
        int assign = p[i].assign;
        int ct_idx = center_table[assign];
        if (ct_idx >= 0 && ct_idx < K) {
            work_mem[ct_idx] += (current_cost - x_cost);
        }
    }
}

__kernel void pgain_finalize_kernel(
    global Point_Struct* p,
    const global float* coord,
    const global int* center_table,
    const global char* switch_membership,
    const global float* gl_lower,
    long x,
    int K,
    int num,
    int dim) {

    int i = get_global_id(0);
    if (i >= num) return;

    int assign = p[i].assign;
    int ct_idx = center_table[assign];

    bool close_center = (ct_idx >= 0 && ct_idx < K && gl_lower[ct_idx] > 0.0f);

    if (switch_membership[i] == 1 || close_center) {
        float new_cost = 0.0f;
        for (int d = 0; d < dim; d++) {
            float diff = coord[d * num + i] - coord[d * num + x];
            new_cost += diff * diff;
        }
        p[i].cost = new_cost * p[i].weight;
        p[i].assign = x;
    }
}

__kernel void update_centers_kernel(
    global char* is_center,
    const global int* center_table,
    const global float* gl_lower,
    int num) {

    int i = get_global_id(0);
    if (i >= num) return;

    int ct_idx = center_table[i];
    if (is_center[i] && ct_idx >= 0 && gl_lower[ct_idx] > 0.0f) {
        is_center[i] = 0;
    }
}

__kernel void set_center_kernel(
    global char* is_center,
    long x,
    int num) {
    if (x < num) {
        is_center[x] = 1;
    }
}
